local typeOfSkeletonAnimation = typeof(Spine.Unity.SkeletonAnimation)
local typeOfSkeletonGraphic = typeof(Spine.Unity.SkeletonGraphic)
local typeofGameObject = typeof(UnityEngine.GameObject)

local CS = CS
------------------------------------------------------------------
---@class LPoolItem
local LPoolItem = LxClass("LPoolItem", nil)
-----------------------------------------------------------------
---
function LPoolItem:LPoolItem(parentTrans,templateRootTrans,args)
	-- 都让在模板节点里，看起来分组好看一些
	self._parentTrans = parentTrans
	self._templateRootTrans = templateRootTrans
	self._args = args
	self._bundleName = nil
	self._itemKey = nil
	self._path = nil
	self._name = nil
	self._loadedFuncList = {}
	self._itemFuncList = {}
	self._itemList = {}
	self._itemTemplate = nil
	self._itemTemplateGo = nil
	self._itemSize = 0

	self._defaultSize = 3

	self._bInstanted = nil
	self._isLoading = nil
	
	self._returnTimeMap = {}
	self._lastReturnTime = 0

	self._prepareSize = 0

	self._outItemCnt = 0

	---@type LxResRequester
	self._resRequester = nil
end

function LPoolItem:SetPrepareSize(prepareSize)
	self._prepareSize = prepareSize or 0
end

function LPoolItem:GetAssetPath()
	if self._args then
		return self._args:GetItemPath()
	else
		return nil
	end
	
end

function LPoolItem:SetDefaultSize(size)
	size = size or 1
	if size < 1 then size = 1 end
	self._defaultSize = size
end

function LPoolItem:GrowUpPool(upSize)
	local size = self._itemSize
	local oldSize = size

	local upSize = upSize or self._defaultSize

	if size == 0 then
		size = upSize
	else
		size = size + upSize
	end
	local itemList = self._itemList
	local parent = self._parentTrans
	local k = oldSize
	local ostime = os.time()
	local itemName = self._args:GetItemName()
	local go = self._itemTemplateGo
	while k < size do
		--local asset = LxResUtil.NewObject(self._itemTemplate.gameObject, self._bundleName, true)
		local asset = LxResUtil.NewObject(go)
		asset.name = itemName
		local assetTrans = asset.transform
		CS.SetParentTrans(assetTrans,parent)
		self:SetItemVisible(assetTrans, false)
		table.insert(itemList,assetTrans)
		self._returnTimeMap[assetTrans] = ostime
		k = k + 1
	end
end

--会隐藏 、显示的不用处理
function LPoolItem:CheckTemplateSpine(assetTrans)
	if not self._isObjectActive then return end
	local args = self._args
	if not args then return end

	local itemType = args:GetItemType()

	if not itemType then return end

	if itemType == LPoolItemConst.TYPE_SPINE then
		local skeletonAnimation = assetTrans:GetComponent(typeOfSkeletonAnimation)
		if skeletonAnimation then
			skeletonAnimation.freeze = true
		end
	elseif itemType == LPoolItemConst.TYPE_SPINE_UI then
		local skeletonAnimation = assetTrans:GetComponent(typeOfSkeletonGraphic)
		if skeletonAnimation then
			skeletonAnimation.freeze = true
		end
	end
end

function LPoolItem:SetItemVisible(assetTrans, bActive)
	if not self._isObjectActive then
		CS.ShowObject(assetTrans,bActive)
	end
end

function LPoolItem:GetItem()
	if not self._bInstanted then return end
	if not self:IsValid() then return end

	local itemList = self._itemList
	if #itemList == 0 then
		self:GrowUpPool()
	end
	local item = itemList[1]
	table.remove(itemList,1)

	self:SetItemVisible(item, true)

	self._returnTimeMap[item] = nil
	self._outItemCnt = self._outItemCnt + 1
	return item
end

function LPoolItem:ReturnItem(itemTrans)
	if self._isDestroy then return false end
	CS.SetParentTrans(itemTrans,self._parentTrans)

	self:SetItemVisible(itemTrans,false)

	table.insert(self._itemList,itemTrans)
	local ostime = os.time()
	self._returnTimeMap[itemTrans] = ostime
	self._outItemCnt = self._outItemCnt - 1
	self._lastReturnTime = ostime
	return true
end

function LPoolItem:ClearLongTimeUnused(clearSpaceTime)
	local itemList = self._itemList
	if #itemList == 0 then
		return
	end
	clearSpaceTime = clearSpaceTime or 0
	
	local item = itemList[1]
	if item then
		local curTime = os.time()
		local returnTime = self._returnTimeMap[item] or curTime
		local spaceTime = curTime - returnTime
		while spaceTime > clearSpaceTime do
			table.remove(itemList, 1)
			--LxResUtil.DestroyObject(item, self._bundleName)
			LxResUtil.DestroyObject(item.gameObject)
			
			item = itemList[1]
			returnTime = self._returnTimeMap[item] or curTime
			spaceTime = curTime - returnTime
		end
	end
end

function LPoolItem:CheckClearUnused(clearSpaceTime)
	if not self._bInstanted then return false end
	clearSpaceTime = clearSpaceTime or 0
	if self._outItemCnt <= 0 then
		if os.time() - self._lastReturnTime >= clearSpaceTime then
			return true
		end
	end
	return false
end

function LPoolItem:DestroyFirstItem()
	local itemList = self._itemList
	if #itemList == 0 then
		--LxResUtil.DestroyObject(self._itemTemplate, self._bundleName)
		LxResUtil.DestroyObject(self._itemTemplateGo)
		return -1
	end
	local item = table.remove(itemList)
	--LxResUtil.DestroyObject(item, self._bundleName)
	LxResUtil.DestroyObject(item.gameObject)
	return #itemList
end

function LPoolItem:CheckPrepareSize()
	if self._prepareSize <= 0 then
		return
	end
	self:GrowUpPool(self._prepareSize)
end

function LPoolItem:StartLoad()
	local args = self._args
	self._isLoading = true

	if self._resRequester then
		self._resRequester:Dispose()
		self._resRequester = nil
	end

	local assetPath = args:GetItemPath()

	self._resRequester = LxResUtil.GetAssetRequester(assetPath, typeofGameObject, function(obj)
		self._isLoading = false
		self:OnLoaded(obj)
	end)
	self._resRequester:StartRequester()
end

function LPoolItem:OnLoaded(asset, assetPath, bundleName)
	if self._isDestroy then return end
	self._bundleName = bundleName
	self._bInstanted = true
	local parentTrans = self._templateRootTrans
	if asset and parentTrans and CS.IsValidObject(parentTrans) then
		--local instanceGo = LxResUtil.NewObject(asset, bundleName)
		local instanceGo = LxResUtil.NewObject(asset)
		instanceGo.name = self._args:GetItemName()
		local instanceTrans = instanceGo.transform
		self._itemTemplate = instanceTrans
		self._itemTemplateGo = instanceGo

		--模板也拿出去用，归还之前，需要删除身上挂载的东西
		--self:ReturnItem(instanceTrans)
		CS.SetParentTrans(self._itemTemplate,parentTrans)

		self:CheckTemplateSpine(self._itemTemplate)

		self:SetItemVisible(self._itemTemplate,false)

		self:CheckPrepareSize()

		local funcList = self._loadedFuncList
		self._loadedFunc = {}
		for k,v in ipairs(funcList) do
			v(self)
		end

		local itemFuncList = self._itemFuncList
		self._itemFuncList = {}
		local args = self._args
		for k,v in ipairs(itemFuncList) do
			v(self:GetItem(),args)
		end
	else
		local funcList = self._loadedFuncList
		self._loadedFunc = {}
		for k,v in ipairs(funcList) do
			v(self)
		end

		local itemFuncList = self._itemFuncList
		self._itemFuncList = {}
		local args = self._args
		for k,v in ipairs(itemFuncList) do
			v(nil,args)
		end
	end
end

function LPoolItem:IsInstanted()
	return self._bInstanted
end

function LPoolItem:IsValid()
	if not self._itemTemplate then
		return false
	end
	if self:IsDestroy() then
		return false
	end
	return true
end

function LPoolItem:IsLoading()
	return self._isLoading
end

function LPoolItem:IsDestroy()
	return self._isDestroy
end

function LPoolItem:AddLoadedFunc(func)
	if self._isDestroy then return end
	if func then
		table.insert(self._loadedFuncList,func)
		return true
	end
	return false
end

function LPoolItem:AddItemFunc(func)
	if self._isDestroy then return end
	if func then
		if self:IsInstanted() and not self:IsValid() then
			func(nil,self._args)
			return
		end
		table.insert(self._itemFuncList,func)
	end
end

function LPoolItem:SetObjectActive(isObjectActive)
	self._isObjectActive = isObjectActive
end

------------------------------------------------------------------
function LPoolItem:ClearItem()
	if not CS.IsValidObject(self._parentTrans) then
		return
	end
	for k,v in ipairs(self._itemList) do
		--LxResUtil.DestroyObject(v, self._bundleName,true)
		LxResUtil.DestroyObject(v.gameObject)
	end
	if CS.IsValidObject(self._itemTemplate) then
		--LxResUtil.DestroyObject(self._itemTemplate, self._bundleName)
		LxResUtil.DestroyObject(self._itemTemplateGo)
	end

end

function LPoolItem:Destroy()
	local args = self._args

	if self._resRequester then
		self._resRequester:Dispose()
		self._resRequester = nil
	end

	table.removeall(self)
	self._args = args
	self._isDestroy = true
end

return LPoolItem